@keyframes flip-enter {
  0%   { transform: perspective(1200px) rotateY(90deg); opacity: 0; }
  100% { transform: perspective(1200px) rotateY(0deg);  opacity: 1; }
}
@keyframes flip-exit {
  0%   { transform: perspective(1200px) rotateY(0deg);   opacity: 1; }
  100% { transform: perspective(1200px) rotateY(-90deg); opacity: 0; }
}

html.flip::view-transition-old(root) {
  animation: flip-exit 0.6s cubic-bezier(0.4, 0, 0.2, 1) forwards;
  transform-origin: center left;
}
html.flip::view-transition-new(root) {
  animation: flip-enter 0.6s cubic-bezier(0.4, 0, 0.2, 1) forwards;
  transform-origin: center right;
}

import { TransitionLink } from "@/components/transition-link"
import "./transition.css"

export function FlipLink({ href, children, className }: {
  href: string
  children: React.ReactNode
  className?: string
}) {
  return (
    <TransitionLink
      href={href}
      transitionClass="flip"
      className={className}
    >
      {children}
    </TransitionLink>
  )
}

